     2→"use client";
     3→
     4→import { useEffect, useState } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { useRouter } from "next/navigation";
     7→import { StatsCards } from "@/components/dashboard/stats-cards";
     8→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     9→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
    10→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    11→import { DiscoverySection } from "@/components/dashboard/discovery-section";
    12→import { projects as projectsApi } from "@/lib/api/client";
    13→import { Search } from "lucide-react";
    14→
    15→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    16→
    17→export default function DashboardPage() {
    18→  const router = useRouter();
    19→  const [repoUrl, setRepoUrl] = useState("");
    20→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    21→    projectsApi.list()
    22→  );
    23→
    24→  // Listen to SSE events and revalidate dashboard data on new releases
    25→  useEffect(() => {
    26→    let es: EventSource | null = null;
    27→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    28→
    29→    function connect() {
    30→      try {
    31→        es = new EventSource(`${SSE_BASE}/events`);
    32→        es.onmessage = () => {
    33→          // Revalidate all dashboard SWR keys on any event
    34→          mutate((key) => typeof key === "string" && (
    35→            key === "stats" ||
    36→            key.startsWith("trend-") ||
    37→            key === "unified-feed"
