     1→package auth
     2→
     3→import (
     4→	"context"
     5→	"crypto/hmac"
     6→	"crypto/sha256"
     7→	"encoding/hex"
     8→	"errors"
     9→	"fmt"
    10→	"log/slog"
    11→	"strings"
    12→	"time"
    13→
    14→	"github.com/jackc/pgx/v5/pgxpool"
    15→)
    16→
    17→const sessionDuration = 7 * 24 * time.Hour
    18→
    19→// SessionStore manages server-side sessions in PostgreSQL.
    20→type SessionStore struct {
    21→	pool   *pgxpool.Pool
    22→	secret string
    23→}
    24→
    25→// NewSessionStore creates a new session store.
    26→func NewSessionStore(pool *pgxpool.Pool, secret string) *SessionStore {
    27→	return &SessionStore{pool: pool, secret: secret}
    28→}
    29→
    30→// SignSessionCookie produces "sessionID.hmacHex".
    31→func SignSessionCookie(sessionID, secret string) string {
    32→	mac := hmac.New(sha256.New, []byte(secret))
    33→	mac.Write([]byte(sessionID))
    34→	sig := hex.EncodeToString(mac.Sum(nil))
    35→	return sessionID + "." + sig
    36→}
    37→
    38→// ParseSessionCookie validates "sessionID.hmacHex" and returns the sessionID.
    39→func ParseSessionCookie(cookie, secret string) (string, error) {
    40→	idx := strings.LastIndex(cookie, ".")
    41→	if idx < 0 {
    42→		return "", errors.New("malformed session cookie")
    43→	}
    44→	sessionID := cookie[:idx]
    45→	sig := cookie[idx+1:]
    46→
    47→	mac := hmac.New(sha256.New, []byte(secret))
    48→	mac.Write([]byte(sessionID))
    49→	expected := hex.EncodeToString(mac.Sum(nil))
    50→
    51→	if !hmac.Equal([]byte(sig), []byte(expected)) {
    52→		return "", errors.New("invalid session signature")
    53→	}
    54→	return sessionID, nil
    55→}
    56→
    57→// CreateSession creates a new session for the given user and returns the signed cookie value.
    58→func (s *SessionStore) CreateSession(ctx context.Context, userID string) (string, time.Time, error) {
    59→	var sessionID string
    60→	expiresAt := time.Now().Add(sessionDuration)
    61→	err := s.pool.QueryRow(ctx,
    62→		`INSERT INTO sessions (user_id, expires_at) VALUES ($1, $2) RETURNING id`,
    63→		userID, expiresAt,
    64→	).Scan(&sessionID)
    65→	if err != nil {
    66→		return "", time.Time{}, fmt.Errorf("create session: %w", err)
    67→	}
    68→	return SignSessionCookie(sessionID, s.secret), expiresAt, nil
    69→}
    70→
    71→// ValidateSession parses the cookie, verifies the HMAC, looks up the session, and returns the user.
    72→func (s *SessionStore) ValidateSession(ctx context.Context, cookie string) (*User, error) {
    73→	sessionID, err := ParseSessionCookie(cookie, s.secret)
    74→	if err != nil {
    75→		return nil, err
    76→	}
    77→
    78→	var u User
    79→	err = s.pool.QueryRow(ctx, `
    80→		SELECT u.id, u.github_id, u.github_login, COALESCE(u.name,''), COALESCE(u.avatar_url,'')
    81→		FROM sessions s JOIN users u ON u.id = s.user_id
    82→		WHERE s.id = $1 AND s.expires_at > NOW()
    83→	`, sessionID).Scan(&u.ID, &u.GitHubID, &u.GitHubLogin, &u.Name, &u.AvatarURL)
    84→	if err != nil {
    85→		return nil, fmt.Errorf("invalid or expired session: %w", err)
    86→	}
    87→	return &u, nil
    88→}
    89→
    90→// DeleteSession removes a session by cookie value.
    91→func (s *SessionStore) DeleteSession(ctx context.Context, cookie string) error {
    92→	sessionID, err := ParseSessionCookie(cookie, s.secret)
    93→	if err != nil {
    94→		return err
    95→	}
    96→	_, err = s.pool.Exec(ctx, `DELETE FROM sessions WHERE id = $1`, sessionID)
    97→	return err
    98→}
    99→
   100→// CleanupExpired removes all expired sessions. Intended to be called periodically.
   101→func (s *SessionStore) CleanupExpired(ctx context.Context) (int64, error) {
   102→	tag, err := s.pool.Exec(ctx, `DELETE FROM sessions WHERE expires_at < NOW()`)
   103→	if err != nil {
   104→		return 0, err
   105→	}
   106→	return tag.RowsAffected(), nil
   107→}
   108→
   109→// RunCleanupLoop deletes expired sessions every hour until ctx is cancelled.
   110→func (s *SessionStore) RunCleanupLoop(ctx context.Context) {
   111→	ticker := time.NewTicker(1 * time.Hour)
   112→	defer ticker.Stop()
   113→	for {
   114→		select {
   115→		case <-ctx.Done():
   116→			return
   117→		case <-ticker.C:
   118→			if n, err := s.CleanupExpired(ctx); err != nil {
   119→				slog.Error("session cleanup failed", "err", err)
   120→			} else if n > 0 {
   121→				slog.Info("cleaned up expired sessions", "count", n)
   122→			}
   123→		}
   124→	}
   125→}
