    54→// NewDependencyExtractor creates a DependencyExtractor for the configured provider.
    55→func NewDependencyExtractor(ctx context.Context, cfg ExtractorConfig) (*DependencyExtractor, error) {
    56→	switch cfg.Provider {
    57→	case "gemini", "":
    58→		if cfg.GoogleAPIKey == "" {
    59→			return nil, fmt.Errorf("GOOGLE_API_KEY is required for gemini provider")
    60→		}
    61→		client, err := genai.NewClient(ctx, &genai.ClientConfig{
    62→			APIKey:  cfg.GoogleAPIKey,
    63→			Backend: genai.BackendGeminiAPI,
    64→		})
    65→		if err != nil {
    66→			return nil, fmt.Errorf("create genai client: %w", err)
    67→		}
    68→		model := cfg.Model
    69→		if model == "" {
    70→			model = "gemini-2.0-flash"
    71→		}
    72→		return &DependencyExtractor{
    73→			provider:     "gemini",
    74→			model:        model,
    75→			geminiClient: client,
    76→		}, nil
    77→
    78→	case "openai":
    79→		if cfg.OpenAIAPIKey == "" {
    80→			return nil, fmt.Errorf("OPENAI_API_KEY is required for openai provider")
    81→		}
    82→		baseURL := cfg.OpenAIBaseURL
    83→		if baseURL == "" {
    84→			baseURL = "https://api.openai.com/v1"
    85→		}
    86→		model := cfg.Model
    87→		if model == "" {
    88→			model = "gpt-4o-mini"
    89→		}
    90→		return &DependencyExtractor{
    91→			provider:      "openai",
    92→			model:         model,
    93→			openaiAPIKey:  cfg.OpenAIAPIKey,
    94→			openaiBaseURL: baseURL,
    95→			httpClient:    &http.Client{},
    96→		}, nil
    97→
    98→	default:
    99→		return nil, fmt.Errorf("unknown LLM provider: %q (supported: gemini, openai)", cfg.Provider)
   100→	}
   101→}
