   177→func (e *DependencyExtractor) extractOpenAI(ctx context.Context, prompt string) (string, error) {
   178→	temp := float32(0.1)
   179→	reqBody := openaiResponsesRequest{
   180→		Model: e.model,
   181→		Input: []openaiInput{
   182→			{Type: "message", Role: "user", Content: prompt},
   183→		},
   184→		Instructions: extractionSystemPrompt,
   185→		Temperature:  &temp,
   186→		Store:        false,
   187→	}
   188→
   189→	body, err := json.Marshal(reqBody)
   190→	if err != nil {
   191→		return "", fmt.Errorf("marshal request: %w", err)
   192→	}
   193→
   194→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, e.openaiBaseURL+"/responses", bytes.NewReader(body))
   195→	if err != nil {
   196→		return "", fmt.Errorf("create http request: %w", err)
   197→	}
   198→	httpReq.Header.Set("Content-Type", "application/json")
   199→	httpReq.Header.Set("Authorization", "Bearer "+e.openaiAPIKey)
   200→
   201→	httpResp, err := e.httpClient.Do(httpReq)
   202→	if err != nil {
   203→		return "", fmt.Errorf("http request: %w", err)
   204→	}
   205→	defer httpResp.Body.Close()
   206→
   207→	respBody, err := io.ReadAll(httpResp.Body)
   208→	if err != nil {
   209→		return "", fmt.Errorf("read response: %w", err)
   210→	}
   211→
   212→	if httpResp.StatusCode != http.StatusOK {
   213→		return "", fmt.Errorf("OpenAI API returned status %d: %s", httpResp.StatusCode, string(respBody))
   214→	}
   215→
   216→	var resp openaiResponsesResponse
   217→	if err := json.Unmarshal(respBody, &resp); err != nil {
   218→		return "", fmt.Errorf("unmarshal response: %w", err)
   219→	}
   220→
   221→	if resp.Error != nil {
   222→		return "", fmt.Errorf("OpenAI API error: %s (type=%s)", resp.Error.Message, resp.Error.Type)
   223→	}
   224→
   225→	// Extract text from message output
   226→	for _, item := range resp.Output {
   227→		if item.Type == "message" {
   228→			for _, c := range item.Content {
   229→				if c.Type == "output_text" && c.Text != "" {
   230→					return c.Text, nil
   231→				}
   232→			}
   233→		}
   234→	}
   235→
   236→	return "", fmt.Errorf("empty response from OpenAI")
   237→}
