   239→// BuildExtractionPrompt constructs the user prompt from dependency files.
   240→func BuildExtractionPrompt(files []DependencyFile) string {
   241→	var b strings.Builder
   242→	b.WriteString("Extract all dependencies from these files:\n\n")
   243→	for _, f := range files {
   244→		b.WriteString(fmt.Sprintf("--- %s ---\n%s\n\n", f.Path, f.Content))
   245→	}
   246→	return b.String()
   247→}
   248→
   249→// ParseDependencies parses the LLM response into ScannedDependency structs.
   250→// Handles raw JSON arrays and markdown-fenced JSON.
   251→func ParseDependencies(raw []byte) ([]models.ScannedDependency, error) {
   252→	text := strings.TrimSpace(string(raw))
   253→
   254→	// Strip markdown code fences if present
   255→	if strings.HasPrefix(text, "```") {
   256→		lines := strings.Split(text, "\n")
   257→		if len(lines) > 2 {
   258→			// Remove first and last lines (``` markers)
   259→			lines = lines[1 : len(lines)-1]
   260→			// If last line is also ```, it was already removed
   261→			if len(lines) > 0 && strings.TrimSpace(lines[len(lines)-1]) == "```" {
   262→				lines = lines[:len(lines)-1]
   263→			}
   264→			text = strings.Join(lines, "\n")
   265→		}
   266→	}
   267→
   268→	var deps []models.ScannedDependency
   269→	if err := json.Unmarshal([]byte(text), &deps); err != nil {
   270→		return nil, fmt.Errorf("parse dependencies JSON: %w\nraw: %s", err, text)
   271→	}
   272→	return deps, nil
   273→}
